/* global Office */

import type { DataFlowEdge, DataFlowModel } from "../core/dataFlow";

type ParentMessage =
  | { action: "setDataFlow"; model: DataFlowModel | null }
  | { action: "error"; message: string };

let model: DataFlowModel | null = null;
let selectedKey = "";

function send(
  message:
    | { action: "ready" }
    | { action: "highlightFlowLink"; fromSheet: string; toSheet: string }
    | { action: "navigateFlowLink"; fromSheet: string; toSheet: string }
    | { action: "exportDataFlow" }
    | { action: "close" }
): void {
  Office.context.ui.messageParent(JSON.stringify(message));
}

function parseMessage(raw: unknown): ParentMessage | null {
  if (typeof raw !== "string") return null;
  try {
    const parsed = JSON.parse(raw) as ParentMessage;
    if (parsed.action === "setDataFlow" || parsed.action === "error") return parsed;
  } catch {
    return null;
  }
  return null;
}

function render(): void {
  const body = document.getElementById("matrixBody");
  const head = document.getElementById("matrixHead");
  if (!(body instanceof HTMLTableSectionElement) || !(head instanceof HTMLTableSectionElement)) return;
  body.textContent = "";
  head.textContent = "";
  if (!model) return;

  const edges = new Map(model.edges.map((edge) => [edgeKey(edge.fromSheet, edge.toSheet), edge]));
  const headerRow = document.createElement("tr");
  headerRow.appendChild(document.createElement("th"));
  for (const sheet of model.sheets) {
    const th = document.createElement("th");
    th.className = "column-sheet";
    th.title = renderSheetName(sheet.name, sheet.hidden);
    const span = document.createElement("span");
    span.textContent = renderSheetName(sheet.name, sheet.hidden);
    th.appendChild(span);
    headerRow.appendChild(th);
  }
  head.appendChild(headerRow);

  for (const from of model.sheets) {
    const tr = document.createElement("tr");
    const rowHead = document.createElement("th");
    rowHead.className = "row-sheet";
    rowHead.textContent = renderSheetName(from.name, from.hidden);
    rowHead.title = rowHead.textContent;
    tr.appendChild(rowHead);
    for (const to of model.sheets) {
      const key = edgeKey(from.name, to.name);
      const edge = edges.get(key);
      const td = document.createElement("td");
      td.className = from.name === to.name ? "self" : "";
      if (key === selectedKey) td.classList.add("selected");
      if (edge) {
        td.classList.add("link");
        td.textContent = String(edge.count);
        td.title = `${renderSheetName(from.name, from.hidden)} -> ${renderSheetName(to.name, to.hidden)}: ${edge.count}`;
        td.addEventListener("click", () => selectEdge(edge));
        td.addEventListener("dblclick", () => send({ action: "navigateFlowLink", fromSheet: edge.fromSheet, toSheet: edge.toSheet }));
      }
      tr.appendChild(td);
    }
    body.appendChild(tr);
  }
  setStatus(`${model.sheets.length} sheets, ${model.edges.length} links`);
}

function selectEdge(edge: DataFlowEdge): void {
  selectedKey = edgeKey(edge.fromSheet, edge.toSheet);
  send({ action: "highlightFlowLink", fromSheet: edge.fromSheet, toSheet: edge.toSheet });
  setStatus(`${edge.fromSheet} -> ${edge.toSheet}: ${edge.count} formula cells`);
  render();
}

function applyModel(next: DataFlowModel | null): void {
  model = next;
  selectedKey = "";
  const title = document.getElementById("title");
  if (title) title.textContent = "Data Flow";
  render();
}

function setStatus(message: string): void {
  const status = document.getElementById("status");
  if (status) status.textContent = message;
}

function edgeKey(fromSheet: string, toSheet: string): string {
  return `${fromSheet}\u0000${toSheet}`;
}

function renderSheetName(name: string, hidden: boolean): string {
  return hidden ? `${name} (hidden)` : name;
}

Office.onReady(() => {
  document.getElementById("closeBtn")?.addEventListener("click", () => send({ action: "close" }));
  document.getElementById("exportLink")?.addEventListener("click", (event) => {
    event.preventDefault();
    send({ action: "exportDataFlow" });
  });
  Office.context.ui.addHandlerAsync(
    Office.EventType.DialogParentMessageReceived,
    (arg) => {
      const message = parseMessage("message" in arg ? arg.message : null);
      if (!message) return;
      if (message.action === "setDataFlow") applyModel(message.model);
      if (message.action === "error") setStatus(message.message);
    },
    () => send({ action: "ready" })
  );
});
